const QentlRuntime={version:"0.3.0",Types:{NULL:"null",INTEGER:"integer",FLOAT:"float",BOOLEAN:"boolean",STRING:"string",ARRAY:"array",OBJECT:"object",FUNCTION:"function"},memory:{used:0,peak:0,allocations:[],alloc(e){this.used+=e,this.used>this.peak&&(this.peak=this.used);const t=Date.now()+Math.random();return this.allocations.push({id:t,size:e}),{id:t,size:e}},free(e){const t=this.allocations.findIndex(s=>s.id===e.id);t>=0&&(this.used-=this.allocations[t].size,this.allocations.splice(t,1))},stats(){return{used:this.used,peak:this.peak,count:this.allocations.length}}},value:{create(e,t){return{type:e,value:t}},getType(e){return e?.type||this.Types.NULL},isTruthy(e){if(!e)return!1;switch(e.type){case this.Types.NULL:return!1;case this.Types.BOOLEAN:return e.value;case this.Types.INTEGER:return e.value!==0;case this.Types.STRING:return e.value.length>0;default:return!0}},clone(e){return e?JSON.parse(JSON.stringify(e)):null}},bytecode:{load(e){return{source:e,timestamp:Date.now()}},execute(e){return console.log("Executing bytecode:",e.source),this.value.create(this.Types.INTEGER,0)}},quantum:{state:{qubits:8,coherence:.954,status:"superposition"},getStates(){return{"|0\u27E9":{probability:.5,phase:0},"|1\u27E9":{probability:.5,phase:Math.PI},"|+\u27E9":{probability:.3,phase:Math.PI/4},"|-\u27E9":{probability:.3,phase:-Math.PI/4}}},measure(e){return Math.random()<.5?0:1},entangle(e,t){return{qubits:[e,t],strength:Math.random()*.5+.5}}},models:{QSM:{status:"running",version:"1.0.0"},SOM:{status:"running",version:"1.0.0"},WeQ:{status:"running",version:"1.0.0"},Ref:{status:"running",version:"1.0.0"}}};window.QentlRuntime=QentlRuntime;
